import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.Materializer
import spray.json._

import scala.concurrent.{ExecutionContext, Future}
import scala.concurrent.duration._
import scala.util.{Failure, Success}

case class UrlRequest(url: String)
case class ProxyResponse(status: Int, body: String, headers: Map[String, String])

trait JsonProtocol extends DefaultJsonProtocol {
  implicit val urlRequestFormat: RootJsonFormat[UrlRequest] = jsonFormat1(UrlRequest)
  implicit val proxyResponseFormat: RootJsonFormat[ProxyResponse] = jsonFormat3(ProxyResponse)
}

object WebhookProxyService extends App with JsonProtocol {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: Materializer = Materializer(system)
  implicit val executionContext: ExecutionContext = system.dispatcher

  val allowedSchemes = Set("http", "https")
  val allowedHosts = Set(
    "api.partner1.com",
    "api.partner2.com",
    "webhook.partner3.com"
  )
  val maxContentLength = 10 * 1024 * 1024
  val requestTimeout = 30.seconds

  def isUrlAllowed(url: String): Boolean = {
    try {
      val uri = Uri(url)
      val scheme = uri.scheme.toLowerCase
      val host = uri.authority.host.address().toLowerCase
      
      if (!allowedSchemes.contains(scheme)) {
        return false
      }
      
      if (host == "localhost" || host == "127.0.0.1" || host.startsWith("192.168.") || 
          host.startsWith("10.") || host.startsWith("172.16.") || host == "0.0.0.0" ||
          host.startsWith("[::1]") || host.startsWith("[fc") || host.startsWith("[fd")) {
        return false
      }
      
      allowedHosts.exists(allowed => host == allowed || host.endsWith("." + allowed))
    } catch {
      case _: Exception => false
    }
  }

  def fetchUrl(url: String): Future[ProxyResponse] = {
    if (!isUrlAllowed(url)) {
      return Future.failed(new SecurityException("URL not allowed"))
    }

    val request = HttpRequest(
      method = HttpMethods.GET,
      uri = url,
      headers = List(
        headers.`User-Agent`("WebhookProxy/1.0"),
        headers.`Accept`("application/json, text/plain, */*")
      )
    )

    Http()
      .singleRequest(request)
      .flatMap { response =>
        response.entity.contentLengthOption match {
          case Some(length) if length > maxContentLength =>
            response.discardEntityBytes()
            Future.failed(new RuntimeException(s"Response too large: $length bytes"))
          case _ =>
            Unmarshal(response.entity)
              .to[String]
              .map { body =>
                val filteredHeaders = response.headers
                  .filterNot(h => 
                    h.lowercaseName() == "set-cookie" || 
                    h.lowercaseName() == "authorization" ||
                    h.lowercaseName() == "www-authenticate"
                  )
                  .map(h => h.name() -> h.value())
                  .toMap

                ProxyResponse(
                  status = response.status.intValue(),
                  body = body,
                  headers = filteredHeaders
                )
              }
        }
      }
      .recover {
        case ex: SecurityException => throw ex
        case ex: Exception =>
          ProxyResponse(
            status = 500,
            body = s"Error fetching URL: ${ex.getMessage}",
            headers = Map.empty
          )
      }
  }

  val route =
    pathPrefix("api") {
      path("proxy") {
        post {
          entity(as[String]) { jsonString =>
            try {
              val urlRequest = jsonString.parseJson.convertTo[UrlRequest]
              
              if (urlRequest.url == null || urlRequest.url.trim.isEmpty) {
                complete(StatusCodes.BadRequest -> "URL is required")
              } else {
                val sanitizedUrl = urlRequest.url.trim
                
                onComplete(fetchUrl(sanitizedUrl)) {
                  case Success(proxyResponse) =>
                    complete(StatusCodes.OK -> proxyResponse.toJson.compactPrint)
                  case Failure(ex: SecurityException) =>
                    complete(StatusCodes.Forbidden -> s"Forbidden: ${ex.getMessage}")
                  case Failure(ex) =>
                    complete(StatusCodes.InternalServerError -> s"Error: ${ex.getMessage}")
                }
              }
            } catch {
              case _: DeserializationException =>
                complete(StatusCodes.BadRequest -> "Invalid JSON format")
              case ex: Exception =>
                complete(StatusCodes.BadRequest -> s"Bad request: ${ex.getMessage}")
            }
          }
        }
      } ~
      path("health") {
        get {
          complete(StatusCodes.OK -> "OK")
        }
      }
    }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      println(s"Server online at http://localhost:8080/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }

  sys.addShutdownHook {
    bindingFuture
      .flatMap(_.unbind())
      .onComplete(_ => system.terminate())
  }
}